<?php $bad=$user['role']!=='admin'&&StepSystem\Core\Auth::expired($user['expires_at']);$st=((int)$user['status']===1&&!$bad)?'<span class="badge ok">正常</span>':'<span class="badge bad">不可用</span>';$ex=$user['role']==='admin'?'永久':($user['expires_at']?:'未设置');?><div class="card"><h2>欢迎，<?=h($user['username'])?></h2><div class="dashboard-stats-grid"><div class="stat"><p class="muted">账号状态</p><b><?=$st?></b></div><div class="stat"><p class="muted">有效期至</p><b class="expiry-text"><?=h($ex)?></b></div></div><p class="actions" style="margin-top:18px"><a class="btn green" href="index.php?r=step_settings">步数配置</a><a class="btn light" href="index.php?r=password">修改密码</a><a class="btn" href="index.php?r=logout" onclick="return confirm('确定退出登录吗？')">退出登录</a></p></div><div class="card"><h3>账户信息</h3><p>注册时间：<?=h($user['created_at'])?></p><p>最后登录：<?=h($user['last_login_at']?:'暂无')?></p></div>